class Solution {
public:
    bool canPartitionKSubsets(vector<int>& nums, int k) {
        int sum = 0;
        for (int num : nums) {
            sum += num;
        }
        if (sum % k != 0) {
            return false;
        }
        int targetSum = sum / k;
        vector<bool> used(nums.size(), false);
        return backtrack(nums, used, 0, targetSum, k, 0);
    }

    bool backtrack(vector<int>& nums, vector<bool>& used, int start, int targetSum, int k, int currentSum) {
        if (k == 0) {
            return true;
        }
        if (currentSum == targetSum) {
            return backtrack(nums, used, 0, targetSum, k - 1, 0);
        }
        for (int i = start; i < nums.size(); i++) {
            if (!used[i] && currentSum + nums[i] <= targetSum) {
                used[i] = true;
                if (backtrack(nums, used, i + 1, targetSum, k, currentSum + nums[i])) {
                    return true;
                }
                used[i] = false;
            }
        }
        return false;
    }
};
